sql:
SELECT DISTINCT p.*
FROM products p
INNER JOIN invoice_items ii ON p.product_id = ii.product_id;

SELECT option_name, option_value
FROM product_options
WHERE product_id = 0;

SELECT AVG(total_amount) 
FROM invoices 
WHERE status = 'Completed';

SELECT customers.customer_name, invoices.invoice_id
FROM customers
INNER JOIN invoices ON customers.customer_id = invoices.customer_id;

SELECT customers.customer_name, order_history.status
FROM customers
JOIN order_history ON customers.customer_id = order_history.customer_id;

SELECT total_amount 
FROM invoices 
WHERE invoice_id = '0' AND status = '1';

external_knowledge:
- "treasure chest value" refers to the total amount of the invoices;
- "golden key" metaphorically represents the 'Credit Card' payment method;
- "navigated through the ocean of transactions" implies that the invoices have gone through the payment process successfully, indicated by 'payment_status' being 'Success'.

sql:
SELECT DISTINCT c.customer_name, c.contact_email
FROM customers c
INNER JOIN order_history oh ON c.customer_id = oh.customer_id;

SELECT customer_name 
FROM customers 
WHERE customer_id IN (
    SELECT DISTINCT customer_id 
    FROM invoices
);

SELECT c.customer_name, c.country, oh.status
FROM customers c
JOIN order_history oh ON c.customer_id = oh.customer_id;
